  // ── pixelIcon(id, size, color?) → SVG string ──────────────────
  // Builds the SVG once per call. ~25 icons × ~80 rects = trivial.
  function pixelIcon(id, size, color) {
    size = size || 16;
    color = color || 'currentColor';
    const def = ICONS_BY_ID[id];
    if (!def) {
      // Unknown icon → render an empty square so layout doesn't shift
      return `<svg width="${size}" height="${size}" viewBox="0 0 16 16"></svg>`;
    }
    const v = def.v || 16;
    let rects = '';
    for (let i = 0; i < def.d.length; i++) {
      const parts = def.d[i].split(' ');
      rects += `<rect x="${parts[0]}" y="${parts[1]}" width="1" height="1" fill="${color}"/>`;
    }
    return `<svg width="${size}" height="${size}" viewBox="0 0 ${v} ${v}" shape-rendering="crispEdges" style="display:block">${rects}</svg>`;
  }

  // Index for fast lookup
  const ICONS_BY_ID = {};
